export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/**
 * Full color palette for a named theme.
 *
 * Fields are split into two groups:
 * - Base tokens (override the standard CSS variables used by shadcn/Tailwind)
 * - Surface-specific tokens (new variables for sidebar, editor, terminal, status bar)
 *
 * All values must be concrete CSS color strings (hex, oklch, rgba, etc.) so
 * they can be set directly via `element.style.setProperty`.
 */
export interface ThemeColors {
  // ── Base tokens (map to existing CSS variable names) ──────────────────────
  background: string;
  foreground: string;
  card: string;
  cardForeground: string;
  primary: string;
  primaryForeground: string;
  accent: string;
  accentForeground: string;
  muted: string;
  mutedForeground: string;
  border: string;
  input: string;
  ring: string;

  // ── Surface-specific tokens ────────────────────────────────────────────────
  sidebar: string;
  sidebarForeground: string;
  editorBackground: string;
  editorForeground: string;
  terminalBackground: string;
  terminalForeground: string;
  statusBarBackground: string;
  statusBarForeground: string;

  // ── Mode ──────────────────────────────────────────────────────────────────
  /** Determines whether the `.dark` CSS class is applied. */
  mode: "light" | "dark";
}

export interface ThemeDefinition {
  id: ThemeId;
  /** Human-readable display name shown in the theme selector. */
  name: string;
  colors: ThemeColors;
}

// ── Built-in theme definitions ──────────────────────────────────────────────

const T3_LIGHT: ThemeDefinition = {
  id: "t3-light",
  name: "T3 Light",
  colors: {
    mode: "light",
    background: "#ffffff",
    foreground: "#1a1a2e",
    card: "#f7f7fc",
    cardForeground: "#1a1a2e",
    primary: "oklch(0.488 0.217 264)",
    primaryForeground: "#ffffff",
    accent: "rgba(0,0,0,0.04)",
    accentForeground: "#1a1a2e",
    muted: "rgba(0,0,0,0.04)",
    mutedForeground: "#6b7280",
    border: "rgba(0,0,0,0.08)",
    input: "rgba(0,0,0,0.10)",
    ring: "oklch(0.488 0.217 264)",
    sidebar: "#f0f0f8",
    sidebarForeground: "#1a1a2e",
    editorBackground: "#ffffff",
    editorForeground: "#1a1a2e",
    terminalBackground: "#1e1e2e",
    terminalForeground: "#cdd6f4",
    statusBarBackground: "oklch(0.488 0.217 264)",
    statusBarForeground: "#ffffff",
  },
};

const T3_DARK: ThemeDefinition = {
  id: "t3-dark",
  name: "T3 Dark",
  colors: {
    mode: "dark",
    background: "#0d0d14",
    foreground: "#e8e8f0",
    card: "#111118",
    cardForeground: "#e8e8f0",
    primary: "oklch(0.588 0.217 264)",
    primaryForeground: "#ffffff",
    accent: "rgba(255,255,255,0.04)",
    accentForeground: "#e8e8f0",
    muted: "rgba(255,255,255,0.04)",
    mutedForeground: "#9090a0",
