import { BUILT_IN_THEMES, type ThemeId } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/**
 * A list of theme cards with color swatches, one per built-in theme.
 * Designed to be embedded in a settings section.
 */
export function ThemeSelector() {
  const { themeId, setThemeId } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme selection">
      {BUILT_IN_THEMES.map((theme) => {
        const selected = themeId === theme.id;
        const { colors } = theme;

        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setThemeId(theme.id as ThemeId)}
          >
            {/* Swatches + name */}
            <span className="flex items-center gap-3">
              <ThemeSwatches
                background={colors.background}
                sidebar={colors.sidebar}
                primary={colors.primary}
              />
              <span className="flex flex-col gap-0.5">
                <span className="text-sm font-medium leading-none">{theme.name}</span>
                <span className="text-xs capitalize text-muted-foreground">{colors.mode}</span>
              </span>
            </span>

            {/* Selected badge */}
            {selected ? (
              <span className="ml-3 shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

// ── Swatch strip ─────────────────────────────────────────────────────────────

interface ThemeSwatchesProps {
  background: string;
  sidebar: string;
  primary: string;
}

function ThemeSwatches({ background, sidebar, primary }: ThemeSwatchesProps) {
  return (
    <span
      className="flex shrink-0 overflow-hidden rounded-md border border-black/10"
      aria-hidden="true"
    >
      <Swatch color={background} title="Background" />
      <Swatch color={sidebar} title="Sidebar" />
      <Swatch color={primary} title="Accent" />
    </span>
  );
}

function Swatch({ color, title }: { color: string; title: string }) {
  return (
    <span
      className="block h-7 w-5"
      style={{ background: color }}
      title={title}
    />
  );
}

