import { useCallback, useEffect, useSyncExternalStore, type ReactNode } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  getThemeById,
  type ThemeColors,
  type ThemeId,
} from "@t3tools/shared/theme";

// ── Storage keys ────────────────────────────────────────────────────────────

/** Current storage key for the named theme selection. */
const THEME_STORAGE_KEY = "t3code:color-theme";
/**
 * Legacy storage key used by the old light/dark/system toggle.
 * Read once for migration; never written.
 */
const LEGACY_THEME_STORAGE_KEY = "t3code:theme";

// ── CSS variable mapping ─────────────────────────────────────────────────────
// Maps ThemeColors field names (excluding `mode`) to CSS custom property names.

const CSS_VAR_MAP: Record<keyof Omit<ThemeColors, "mode">, string> = {
  background: "--background",
  foreground: "--foreground",
  card: "--card",
  cardForeground: "--card-foreground",
  primary: "--primary",
  primaryForeground: "--primary-foreground",
  accent: "--accent",
  accentForeground: "--accent-foreground",
  muted: "--muted",
  mutedForeground: "--muted-foreground",
  border: "--border",
  input: "--input",
  ring: "--ring",
  sidebar: "--theme-sidebar",
  sidebarForeground: "--theme-sidebar-fg",
  editorBackground: "--theme-editor-bg",
  editorForeground: "--theme-editor-fg",
  terminalBackground: "--theme-terminal-bg",
  terminalForeground: "--theme-terminal-fg",
  statusBarBackground: "--theme-statusbar-bg",
  statusBarForeground: "--theme-statusbar-fg",
};

// ── External store ───────────────────────────────────────────────────────────

let listeners: Array<() => void> = [];

function emitChange(): void {
  for (const listener of listeners) listener();
}

/**
 * Reads the stored ThemeId, migrating from the legacy light/dark/system value
 * when the new key has not been set yet.
 */
function getStoredThemeId(): ThemeId {
  if (typeof window === "undefined") return DEFAULT_THEME_ID;

  const raw = localStorage.getItem(THEME_STORAGE_KEY);
  if (raw && getThemeById(raw)) {
    return raw as ThemeId;
  }

  // Migrate from legacy "light" | "dark" | "system" value.
  const legacy = localStorage.getItem(LEGACY_THEME_STORAGE_KEY);
  if (legacy === "light") return "t3-light";
  if (legacy === "dark") return "t3-dark";
  if (legacy === "system") {
    // Map system preference to a concrete dark/light theme.
    try {
      return window.matchMedia("(prefers-color-scheme: dark)").matches
        ? "t3-dark"
        : "t3-light";
    } catch {
      return DEFAULT_THEME_ID;
    }
  }

  return DEFAULT_THEME_ID;
}

/**
 * Applies a named theme by:
 * 1. Toggling the `.dark` CSS class based on the theme's mode.
 * 2. Setting all theme color tokens as inline CSS custom properties on
 *    `document.documentElement` so they override the stylesheet defaults.
 */
function applyTheme(themeId: ThemeId, suppressTransitions = false): void {
  if (typeof document === "undefined") return;

  const theme = getThemeById(themeId) ?? getThemeById(DEFAULT_THEME_ID)!;
  const { colors } = theme;

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle dark mode class (used by CSS rules that can't use CSS variables).
  document.documentElement.classList.toggle("dark", colors.mode === "dark");

  // Apply all color tokens as inline CSS custom properties.
  const style = document.documentElement.style;
  for (const [key, cssVar] of Object.entries(CSS_VAR_MAP) as Array<
    [keyof Omit<ThemeColors, "mode">, string]
  >) {
    style.setProperty(cssVar, colors[key]);
  }

  if (suppressTransitions) {
    // Force reflow so no-transitions takes effect before the class is removed.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function getSnapshot(): ThemeId {
  return getStoredThemeId();
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === THEME_STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// Apply immediately on module load to prevent flash of unstyled content.
applyTheme(getStoredThemeId());

// ── Hook ────────────────────────────────────────────────────────────────────

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const resolvedTheme: "light" | "dark" = getThemeById(themeId)?.colors.mode ?? "dark";

  const setThemeId = useCallback((next: ThemeId) => {
    localStorage.setItem(THEME_STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Re-apply on mount/change as a safety net for SSR/hydration edge cases.
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return { themeId, setThemeId, resolvedTheme } as const;
}

// ── Provider ─────────────────────────────────────────────────────────────────

/**
 * Thin wrapper that re-applies the active theme on mount.
 * No React context is used — theme state lives in localStorage and is read
 * directly by `useTheme`. This component exists purely as a mounting guard
 * and to satisfy the conventional "provider" pattern.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const { themeId } = useTheme();

  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  // eslint-disable-next-line react/jsx-no-useless-fragment
  return <>{children}</>;
}

// ── Re-export theme catalogue for convenience ─────────────────────────────

export { BUILT_IN_THEMES, DEFAULT_THEME_ID, getThemeById };
export type { ThemeId };

